namespace blink {

// ─── AeonProxy ────────────────────────────────────────────────────────────
AeonProxy* AeonProxy::Create(ExecutionContext* context) {
  return MakeGarbageCollected<AeonProxy>(context);
}

AeonProxy::AeonProxy(ExecutionContext* context)
    : context_(context),
      agent_(MakeGarbageCollected<AeonAgentProxy>(context)),
      llm_(MakeGarbageCollected<AeonLLMProxy>(context)),
      privacy_(MakeGarbageCollected<AeonPrivacyProxy>()),
      memory_(MakeGarbageCollected<AeonMemoryProxy>(context)),
      hive_(MakeGarbageCollected<AeonHiveProxy>(context)),
      self_(MakeGarbageCollected<AeonSelfProxy>(context)) {}

String AeonProxy::version() const { return "1.0.0"; }
String AeonProxy::build() const { return "aeon-cloud-2026"; }
AeonAgentProxy* AeonProxy::agent() const { return agent_; }
AeonLLMProxy* AeonProxy::llm() const { return llm_; }
AeonPrivacyProxy* AeonProxy::privacy() const { return privacy_; }
AeonMemoryProxy* AeonProxy::memory() const { return memory_; }
AeonHiveProxy* AeonProxy::hive() const { return hive_; }
AeonSelfProxy* AeonProxy::self() const { return self_; }

void AeonProxy::Trace(Visitor* visitor) const {
  visitor->Trace(agent_);
  visitor->Trace(llm_);
  visitor->Trace(privacy_);
  visitor->Trace(memory_);
  visitor->Trace(hive_);
  visitor->Trace(self_);
  ScriptWrappable::Trace(visitor);
}

// ─── Shared REST proxy helper ──────────────────────────────────────────────
// All sub-proxies call AeonMind REST API at localhost:7878.
// We use a simple synchronous-to-async bridge via ScriptPromiseResolver.

namespace {

constexpr char kAeonMindBase[] = "http://localhost:7878";
constexpr char kAeonAuthToken[] = "aeon-internal-v1";  // Rotated at browser start

ScriptPromise<IDLString> PostToAeonMind(
    ScriptState* script_state,
    const String& endpoint,
    const String& body) {
  auto* resolver = MakeGarbageCollected<ScriptPromiseResolver<IDLString>>(
      script_state);
  auto promise = resolver->Promise();

  // Resolve via background thread network call
  // In a real build this uses Chromium's URLLoader. Simplified here for patch clarity.
  // The full implementation is in aeon_url_loader_bridge.cc (auto-generated by build).
  
  resolver->Resolve(String("{}"));  // Placeholder — real impl uses URLLoader
  return promise;
}

}  // namespace

// ─── AeonAgentProxy ───────────────────────────────────────────────────────
ScriptPromise<IDLString> AeonAgentProxy::run(
    ScriptState* script_state, const String& task) {
  return PostToAeonMind(script_state, "/task", 
      "{\"task\":\"" + task + "\",\"priority\":\"high\"}");
}

ScriptPromise<IDLString> AeonAgentProxy::queue(
    ScriptState* script_state, const String& task) {
  return PostToAeonMind(script_state, "/task",
      "{\"task\":\"" + task + "\",\"priority\":\"normal\"}");
}

ScriptPromise<IDLString> AeonAgentProxy::status(ScriptState* script_state) {
  return PostToAeonMind(script_state, "/status", "{}");
}

ScriptPromise<IDLBoolean> AeonAgentProxy::stop(ScriptState* script_state) {
  auto* resolver = MakeGarbageCollected<ScriptPromiseResolver<IDLBoolean>>(
      script_state);
  resolver->Resolve(true);
  return resolver->Promise();
}

// ─── AeonLLMProxy ─────────────────────────────────────────────────────────
ScriptPromise<IDLString> AeonLLMProxy::complete(
    ScriptState* script_state, const String& prompt) {
  return PostToAeonMind(script_state, "/llm/complete",
      "{\"prompt\":\"" + prompt + "\"}");
}

ScriptPromise<IDLString> AeonLLMProxy::model(ScriptState* script_state) {
  return PostToAeonMind(script_state, "/llm/model", "{}");
}

// ─── AeonPrivacyProxy ─────────────────────────────────────────────────────
String AeonPrivacyProxy::fingerprint() const {
  return AeonFingerprintSeed::GetCurrentHash();
}

bool AeonPrivacyProxy::refresh() {
  AeonFingerprintSeed::RotateSeed();
  return true;
}

String AeonPrivacyProxy::mode() const {
  return AeonFingerprintSeed::GetMode();
}

bool AeonPrivacyProxy::setMode(const String& mode) {
  AeonFingerprintSeed::SetMode(mode);
  return true;
}

// ─── AeonMemoryProxy ──────────────────────────────────────────────────────
ScriptPromise<IDLBoolean> AeonMemoryProxy::store(
    ScriptState* script_state, const String& key, const String& value) {
  PostToAeonMind(script_state, "/memory/store",
      "{\"key\":\"" + key + "\",\"value\":\"" + value + "\"}");
  auto* resolver = MakeGarbageCollected<ScriptPromiseResolver<IDLBoolean>>(
      script_state);
  resolver->Resolve(true);
  return resolver->Promise();
}

ScriptPromise<IDLString> AeonMemoryProxy::recall(
    ScriptState* script_state, const String& key) {
  return PostToAeonMind(script_state, "/memory/recall",
      "{\"key\":\"" + key + "\"}");
}

ScriptPromise<IDLString> AeonMemoryProxy::search(
    ScriptState* script_state, const String& query) {
  return PostToAeonMind(script_state, "/memory/search",
      "{\"query\":\"" + query + "\"}");
}

ScriptPromise<IDLBoolean> AeonMemoryProxy::forget(
    ScriptState* script_state, const String& key) {
  PostToAeonMind(script_state, "/memory/forget", "{\"key\":\"" + key + "\"}");
  auto* resolver = MakeGarbageCollected<ScriptPromiseResolver<IDLBoolean>>(
      script_state);
  resolver->Resolve(true);
  return resolver->Promise();
}

// ─── AeonHiveProxy ────────────────────────────────────────────────────────
ScriptPromise<IDLUnsignedLong> AeonHiveProxy::peers(ScriptState* script_state) {
  auto* resolver = MakeGarbageCollected<ScriptPromiseResolver<IDLUnsignedLong>>(
      script_state);
  resolver->Resolve(0u);  // Real impl polls AeonHive /status
  return resolver->Promise();
}

ScriptPromise<IDLString> AeonHiveProxy::status(ScriptState* script_state) {
  return PostToAeonMind(script_state, "/hive/status", "{}");
}

// ─── AeonSelfProxy ────────────────────────────────────────────────────────
ScriptPromise<IDLUnsignedLong> AeonSelfProxy::tasksCompleted(
    ScriptState* script_state) {
  auto* resolver = MakeGarbageCollected<ScriptPromiseResolver<IDLUnsignedLong>>(
      script_state);
  resolver->Resolve(0u);
  return resolver->Promise();
}

ScriptPromise<IDLString> AeonSelfProxy::modelVersion(
    ScriptState* script_state) {
  return PostToAeonMind(script_state, "/self/version", "{}");
}

ScriptPromise<IDLDouble> AeonSelfProxy::accuracy(ScriptState* script_state) {
  auto* resolver = MakeGarbageCollected<ScriptPromiseResolver<IDLDouble>>(
      script_state);
  resolver->Resolve(0.0);
  return resolver->Promise();
}

}  // namespace blink
